#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

__kernel void benchmark_func(const class_T seed, __global class_T* c) {
  const size_t gid = get_global_id(0);
  const size_t gsize = get_global_size(0);

#ifdef BLOCK_STRIDED
  const size_t lid = get_local_id(0);
  const size_t group = get_group_id(0);
  const size_t elem_stride = (size_t)blockdim;
  const size_t start =
      group * ((size_t)blockdim * (size_t)ELEMENTS_PER_THREAD * (size_t)FUSION_DEGREE) + lid;
#else
  const size_t elem_stride = gsize;
  const size_t start = gid;
#endif

  class_T sum = (class_T)0;

  for (uint fidx = 0; fidx < (uint)FUSION_DEGREE; ++fidx) {
    for (uint eidx = 0; eidx < (uint)ELEMENTS_PER_THREAD; ++eidx) {
      const size_t linear = (size_t)fidx * (size_t)ELEMENTS_PER_THREAD + (size_t)eidx;
      const size_t idx = start + linear * elem_stride;

      class_T t = c[idx];
      for (uint j = 0; j < (uint)COMPUTE_ITERATIONS; ++j) {
        t = t * t + seed;
      }
      sum += t;
    }
  }

  c[start] = sum;
}
